let start = global.get("start");
let nivel = global.get("NivelActual");
let sp = global.get("SP");
let modo_sim = global.get("modo_sim");
let sp_sim = global.get("SP_sim");
let emerg_alta = global.get("modoEmergencia_alto");
let emerg_baja = global.get("modoEmergencia_bajo");

// =====================================================
// 🚨 EMERGENCIAS (SIEMPRE ACTIVAS, INCLUSO EN OFF)
// =====================================================


// EMERGENCIA NIVEL ALTO → llevar a 60
if (emerg_alta) {
    let sp_emergencia = 60;
    if (nivel <= sp_emergencia) {
        return [{ payload: 0 }, { payload: 0 }]; // ya está en zona segura
    }
    let empty = Math.min(100, Math.round((nivel - sp_emergencia) * 5));
    return [{ payload: 0 }, { payload: empty }];
}

// EMERGENCIA NIVEL BAJO → llevar a 40
if (emerg_baja) {
    let sp_emergencia = 40;
    if (nivel >= sp_emergencia) {
        return [{ payload: 0 }, { payload: 0 }]; // ya está en zona segura
    }
    let fill = Math.min(100, Math.round((sp_emergencia - nivel) * 5));
    return [{ payload: fill }, { payload: 0 }];
}



// =====================================================
// 🟦 SI ESTÁ EN OFF
// =====================================================
if (!start) {
    return [{ payload: 0 }, { payload: 0 }];
}

// =====================================================
// 🟩 CONTROL SIMULADO
// =====================================================

if (modo_sim && start) {
    sp = sp_sim;
}

if (sp === undefined || sp === null) {
    return [{ payload: 0 }, { payload: 0 }];
}

let deadband = 0.5;
let fill = 0;
let empty = 0;

if (nivel < sp - deadband) {
    fill = Math.min(100, Math.round((sp - nivel) * 5));
} else if (nivel > sp + deadband) {
    empty = Math.min(100, Math.round((nivel - sp) * 5));
}

return [
    { payload: fill },
    { payload: empty }
];

let nivel = global.get("NivelActual");

// Histéresis
let prev_alta = global.get("modoEmergencia_alto");
let prev_baja = global.get("modoEmergencia_bajo");
global.set("modoEmergencia_alto", nivel > 70 || (prev_alta && nivel > 60));
global.set("modoEmergencia_bajo", nivel < 30 || (prev_baja && nivel < 40));

// Leer el nuevo estado
let emerg_alta = global.get("modoEmergencia_alto");
let emerg_baja = global.get("modoEmergencia_bajo");

// DESPUÉS
let hay_emerg = !!(emerg_alta || emerg_baja);
let prev_n8n = global.get("prev_emerg_n8n") ?? false;
global.set("prev_emerg_n8n", hay_emerg);

if (hay_emerg !== prev_n8n) {
    // INCIDENCIAS
    let log = global.get("log_incidencias") || [];
    let textoNuevo = hay_emerg
        ? (emerg_alta ? "Emergencia nivel ALTO" : "Emergencia nivel BAJO")
        : "✅ Nivel recuperado - sin emergencia";

    // Evitar duplicados consecutivos
    if (log.length === 0 || log[0].texto !== textoNuevo) {
        log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "⚠️", texto: textoNuevo });
        if (log.length > 20) log.pop();
        global.set("log_incidencias", log);
    }

    msg.payload = {
        nivel,
        fecha : new Date().toLocaleString("sv-SE", {
                    timeZone: "Europe/Madrid",
                    hour12: false
                    }).replace(" ", "T"),

        estado: global.get("start") || 0,
        sp: global.get("SP") || null,
        alarma: emerg_alta ? "nivel alto" : emerg_baja ? "nivel bajo" : "ninguna",
        caudal_entrada: global.get("caudal_entrada_leido") || 0,
        caudal_salida: global.get("caudal_salida_leido") || 0
    };
    return msg;
}
return null;

// Añadir al principio de la función
if (!global.get("estado_factoryio")) return null;

// Nivel actual
let nivel = global.get("NivelActual");

// Fecha actual en ISO
let fecha = new Date().toLocaleString("sv-SE", {
    timeZone: "Europe/Madrid",
    hour12: false
}).replace(" ", "T");


// Estado ON/OFF
let estado = global.get("start") || 0;

// Setpoint actual
let sp = global.get("SP") || null;

// ===============================
// 🚨 GENERAR ALARMA PARA N8N
// ===============================
let emerg_alta = global.get("modoEmergencia_alto");
let emerg_baja = global.get("modoEmergencia_bajo");

let alarma = "ninguna";
if (emerg_alta) alarma = "nivel alto";
else if (emerg_baja) alarma = "nivel bajo";

// Caudales
let caudal_entrada = global.get("caudal_entrada_leido") || 0;
let caudal_salida = global.get("caudal_salida_leido") || 0;

// Construir JSON para n8n
msg.payload = {
    nivel,
    fecha,
    estado,
    sp,
    alarma,
    caudal_entrada,
    caudal_salida
};

return msg;

let running = msg.payload[0]; // true = running, false = parado

let prev = global.get("estado_factoryio") ?? null;
global.set("estado_factoryio", running);

if (running === prev) return null;

let log = global.get("log_incidencias") || [];
log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: running ? "✅" : "🔌", texto: running ? "Factory IO conectado" : "Factory IO desconectado" });
if (log.length > 20) log.pop();
global.set("log_incidencias", log);

if (!running) {
    msg.payload = {
        tipo: "factoryio_parado",
        descripcion: "Factory IO detenido o desconectado",
        nivel: global.get("NivelActual")
    };
} else {
    msg.payload = {
        tipo: "factoryio_running",
        descripcion: "Factory IO en marcha",
        nivel: global.get("NivelActual")
    };
}
return msg;

// FUNCIÓN PARA MENSAJES A ENVIAR POR TELEGRAM
function mensaje(chatId, content) {
    return {
        payload: {
            chatId,
            type: "message",
            content,
            options: { parse_mode: "Markdown" }
        }
    };
}

const cmd = msg.payload?.content?.trim().toLowerCase() || null;
const chatId = msg.payload?.chatId || null;

let start = global.get("start") || 0;
let cambioEstado = false;
let msgTelegram = null;

// ON
if (cmd === "/on") {
    if (!start) {
        global.set("start", true);
        start = true;
        cambioEstado = true;

        let log = global.get("log_incidencias") || [];
        log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "🟢", texto: "Tanque ON" });
        if (log.length > 20) log.pop();
        global.set("log_incidencias", log);

    } else {
        msgTelegram = mensaje(chatId, "ℹ️ El tanque ya está en ON ✅");
    }
}

// OFF
else if (cmd === "/off") {
    if (start) {
        global.set("start", false);
        global.set("SP", undefined);
        global.set("modo_sim", false);
        start = false;
        cambioEstado = true;

        let log = global.get("log_incidencias") || [];
        log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "❌", texto: "Tanque OFF" });
        if (log.length > 20) log.pop();
        global.set("log_incidencias", log);

    } else {
        msgTelegram = mensaje(chatId, "ℹ️ El tanque ya está en OFF ❌");
    }
}

// SP
else if (cmd?.startsWith("/sp") && chatId) {
    if (!start)
        return [mensaje(chatId, "⛔ El tanque está en OFF. Ponlo en ON antes de fijar un SP."), null, null, null];

    const match = cmd.match(/\/sp[:\s]+(\d+(\.\d+)?)/);
    if (!match)
        return [mensaje(chatId, "❌ Formato incorrecto. Usa: /sp: XX"), null, null, null];

    const sp = Number(match[1]);

    if (sp < 30 || sp > 70)
        return [mensaje(chatId, "❌ SP no válido. El rango recomendado es 30–70%"), null, null, null];

    global.set("SP", sp);

    // ✅ NUEVO: registrar cambio de SP
    let log = global.get("log_incidencias") || [];
    log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "🎯", texto: `SP fijado: ${sp}%` });
    if (log.length > 20) log.pop();
    global.set("log_incidencias", log);

    return [mensaje(chatId, `✅ Setpoint recibido: ${sp}%`), null, null, null];
}

// NIVEL
else if (cmd === "/nivel" && chatId) {
    const nivel = global.get("NivelActual");
    msgTelegram = mensaje(chatId, `📏 Nivel actual: ${nivel}%`);
}

// GRÁFICA
else if (cmd?.startsWith("/grafica") && chatId) {

    // Extraer minutos si los hay, por defecto 15
    const match = cmd.match(/\/grafica[:\s]+(\d+)/);
    const minutos = match ? parseInt(match[1]) : 15;

    if (minutos < 1 || minutos > 60)
        return [mensaje(chatId, "❌ Minutos no válidos. Usa un valor entre 1 y 60."), null, null, null];

    msgTelegram = mensaje(chatId, `📊 Generando gráfica de los últimos ${minutos} minutos...`);

    let log = global.get("log_incidencias") || [];
    log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "📈", texto: `Gráfica solicitada (${minutos} min)` });
    if (log.length > 20) log.pop();
    global.set("log_incidencias", log);

    return [msgTelegram, { payload: { chatId, minutos } }, null, null];
}

// SIMULACIÓN
else if (cmd?.startsWith("/sim") && chatId) {
    if (!start)
        return [mensaje(chatId, "Primero pon el tanque en ON!!!"), null, null, null];

    const match = cmd.match(/\/sim[:\s]+(on|off)/);
    if (!match)
        return [mensaje(chatId, "❌ Formato incorrecto. Usa:\n/sim: on\n/sim: off"), null, null, null];

    const modo = match[1] === "on";
    global.set("modo_sim", modo);

    // ✅ NUEVO: al activar sim → SP normal a undefined
    if (modo) {
        global.set("SP", undefined);
    }

    // ✅ NUEVO: registrar cambio de simulación
    let log = global.get("log_incidencias") || [];
    log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "🧪", texto: modo ? "Simulación activada" : "Simulación desactivada" });
    if (log.length > 20) log.pop();
    global.set("log_incidencias", log);

    msgTelegram = mensaje(chatId,
        modo
            ? "🧪 *Simulación activada*\nEl SP ahora será aleatorio entre 0 y 100."
            : "🧪 *Simulación desactivada*\nEl SP vuelve a ser el que tú envíes."
    );

    return [msgTelegram, null, null, modo ? { payload: true } : null];
}

// INFORME
else if (cmd === "/informe") {
    // ✅ NUEVO: registrar envío de informe
    let log = global.get("log_incidencias") || [];
    log.unshift({ hora: new Date().toLocaleTimeString('es-ES'), tipo: "📧", texto: "Informe enviado por correo" });
    if (log.length > 20) log.pop();
    global.set("log_incidencias", log);

    msgTelegram = mensaje(chatId, "📧 Vamos a enviar el informe por correo!!!");
    return [msgTelegram, null, { payload: true }, null];
}

// ESTADO
else if (cmd === "/estado" && chatId) {
    const nivel = global.get("NivelActual");
    const sp = global.get("SP");
    const start = global.get("start");
    const emerg_a = global.get("modoEmergencia_alto");
    const emerg_b = global.get("modoEmergencia_bajo");
    const sim = global.get("modo_sim");

    return [mensaje(chatId,
        `📊 *ESTADO DEL SISTEMA*\n` +
        `• Tanque: ${start ? "ON ✅" : "OFF ❌"}\n` +
        `• Nivel: ${nivel}%\n` +
        `• SP: ${sp ?? "No definido"}\n` +
        `• Simulación: ${sim ? "Activa 🧪" : "Inactiva"}\n` +
        `• Emergencia: ${(emerg_a || emerg_b) ? "⚠️ ACTIVA" : "Sin alarmas ✅"}`
    ), null, null, null];
}


// HELP
else if (cmd === "/help" && chatId) {
    return [mensaje(chatId,
        "📋 *Comandos:*\n" +
        "▶️ /on — Activar tanque\n" +
        "⏹ /off — Detener tanque\n" +
        "📏 /nivel — Ver nivel actual\n" +
        "📊 /estado — Ver estado completo\n" +
        "🎯 /sp: XX — Fijar setpoint (recomendado 30–70%)\n" +
        "📈 /grafica — Gráfica últimos 15 min\n" +
        "📈 /grafica: X — Gráfica últimos X minutos (1–60)\n" +
        "📧 /informe — Informe IA por correo\n" +
        "🧪 /sim: on|off — Modo simulación SP aleatorio\n" +
        "❓ /help — Ver esta ayuda\n\n" +
        "⚠️ Debes activar /on antes de fijar un setpoint o entrar en Modo SIM"
    ), null, null, null];
}

// COMANDO NO RECONOCIDO
else if (chatId) {
    msgTelegram = mensaje(chatId,
        "❌ Comando no reconocido.\n\n📋 *Comandos disponibles:*\n" +
        "▶️ /on — Activar tanque\n" +
        "⏹ /off — Detener tanque\n" +
        "📏 /nivel — Ver nivel actual\n" +
        "📊 /estado — Ver estado completo\n" +
        "🎯 /sp: XX — Fijar setpoint (recomendado 30–70%)\n" +
        "📈 /grafica — Gráfica últimos 15 min\n" +
        "📧 /informe — Informe IA por correo\n" +
        "🧪 /sim: on|off — Modo simulación SP aleatorio\n" +
        "❓ /help — Ver esta ayuda"
    );
}

// Mensaje de estado cuando se cambia Start
if (chatId && cambioEstado) {
    let texto = `ℹ️ Estado actual:\n• Tanque: ${start ? "ON ✅" : "OFF ❌"}`;
    if (start) texto += `\n✅ Ahora puedes enviarme un Setpoint con /sp: XX o poner Modo SIM con /sim:on`;
    msgTelegram = mensaje(chatId, texto);
}

return [msgTelegram, null, null, null];

// Solo generar SP_SIM si la simulación está activa
if (global.get("modo_sim") === true) {

    let sp_sim = Math.floor(Math.random() * 101); // 0–100

    global.set("SP_sim", sp_sim);

    msg.payload = `${sp_sim}`;
    return msg;

} else {
    return null; // no hacer nada si la simulación está apagada
}

let x = global.get("modoEmergencia_alto");
let y = global.get("modoEmergencia_bajo");

msg.payload = (x || y) ? true : false;

return msg;

let x = global.get("NivelActual");
msg.payload = x;
msg.topic = "Nivel actual";
return msg;

let x = global.get("caudal_entrada_leido");

msg.payload = x;

return msg;

let x = global.get("caudal_salida_leido");

msg.payload = x;

return msg;

let x = global.get("SP");
let sim = global.get("modo_sim");

msg.payload = x;
msg.sim = sim ? true : false;

return msg;

let x = global.get("SP_sim");
let sim = global.get("modo_sim");

msg.payload = x;
msg.sim = sim ? true : false;

return msg;

let start = global.get("start");

msg.payload = start ? true : false;

return msg;

let x = global.get("modo_sim");

msg.payload = x ? true : false;

return msg;

let x = global.get("caudal_salida_leido");

msg.payload = x;
msg.topic = "Caudal Salida";

return msg;

let x = global.get("caudal_entrada_leido");

msg.payload = x;
msg.topic = "Caudal Entrada";

return msg;

global.set("start", 0);            // OFF al inicio
global.set("SP", undefined);       // No hay SP hasta que tú lo pongas
global.set("NivelActual", 0);
global.set("caudal_entrada_leido", undefined);
global.set("caudal_salida_leido", undefined);
global.set("modo_sim", false);
global.set("SP_sim", undefined); // SP que se pondrá aleatorio para ver cómo reacciona el tanque

// ← NUEVAS: watchdog comunicación FACTORY IO
global.set("ultimo_nivel_modbus", Date.now()); // ← Date.now()

// Emergencias
global.set("modoEmergencia_alto", null);
global.set("modoEmergencia_bajo", null);
global.set("prev_emerg_n8n", false);

global.set("estado_factoryio", null);

global.set("log_incidencias", []);

return null;

let factoryio = global.get("estado_factoryio");
let ultimo = global.get("ultimo_nivel_modbus") || Date.now();
let segundos = Math.round((Date.now() - ultimo) / 1000);

// Fallo = Factory IO parado O sin datos en 5s
let fallo = factoryio === false || segundos > 5;

msg.payload = { segundos, fallo };
return msg;

let sp = global.get("SP");
let sim = global.get("modo_sim");

if (sim) {
    sp = global.get("SP_sim");
}

if (sp !== undefined) {
    msg.payload = sp;
    msg.topic = "Setpoint";
    return msg;
}

return null;
